#include &lt;stdio.h&gt;
#include &lt;string.h&gt;

void explore_string_types() {
    // 1. Pointer to Read-Only String
    const char *readonly_str = "Immutable"; 
    // readonly_str[0] = 'X'; // Compiler error thanks to 'const'

    // 2. Mutable Stack Array
    // Automatically sized to 8 bytes (7 chars + 1 null terminator)
    char mutable_arr[] = "Mutable";
    mutable_arr[0] = 'X'; // Perfectly legal. Operates on stack memory.

    // 3. String Length vs Memory Size
    // strlen() counts N bytes until it hits \0. (Returns 7)
    // sizeof() measures the entire allocated block. (Returns 8)
    printf("Length: %zu, Size: %zu\n", strlen(mutable_arr), sizeof(mutable_arr));
}

