#include &lt;stdio.h&gt;
#include &lt;string.h&gt;

void build_filepath(const char *dir, const char *file) {
    char path[256];

    // DANGER: strcpy + strcat can overflow if dir+file > 256 bytes.
    // strcpy(path, dir);
    // strcat(path, "/");
    // strcat(path, file);

    // PRO-PATTERN: snprintf handles copying, concatenation, and bounds safely.
    // It guarantees null termination and halts safely if strings are too long.
    int written = snprintf(path, sizeof(path), "%s/%s", dir, file);

    // Advanced: Check if truncation occurred
    if (written >= sizeof(path)) {
        printf("ERROR: Path was truncated.\n");
        return;
    }

    printf("Path: %s\n", path);
}

