#include &lt;stdio.h&gt;
#include &lt;string.h&gt;

void parse_csv(char *line) {
    // strtok_r requires us to provide a variable to hold the iteration state
    char *saveptr;

    // 1st Call: Pass the string. It finds the comma, injects \0, and returns "User"
    char *token = strtok_r(line, ",", &saveptr);

    while (token != NULL) {
        printf("Extracted: %s\n", token);
        // Subsequent Calls: Pass NULL to continue from saveptr
        token = strtok_r(NULL, ",", &saveptr);
    }
}

#include &lt;stdio.h&gt;
#include &lt;stdlib.h&gt;
#include &lt;errno.h&gt;
#include &lt;limits.h&gt;

long parse_safe_int(const char *input) {
    char *endptr;
    errno = 0; // Reset POSIX global error flag before operation

    long val = strtol(input, &endptr, 10);

    // 1. Trap Hardware Overflow/Underflow
    if (errno == ERANGE && (val == LONG_MAX || val == LONG_MIN)) {
        printf("FATAL: Value out of system bounds.\n");
        return -1;
    }

    // 2. Trap Empty Input or No Digits Found
    if (endptr == input) {
        printf("FATAL: No digits were found.\n");
        return -1;
    }

    // 3. Trap Trailing Garbage (e.g., "1234abc")
    if (*endptr != '\0') {
        printf("WARNING: Trailing unparsed characters detected: %s\n", endptr);
    }

    return val;
}

